#include <stdio.h>
#include <string.h>

int minOperations(char *str1, char *str2) {
    int n = strlen(str1);
    int m = strlen(str2);
    int dp[n + 1][m + 1];

    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= m; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = 0;
            } else if (str1[i - 1] == str2[j - 1]) {
                dp[i][j] = 1 + dp[i - 1][j - 1];
            } else {
                dp[i][j] = (dp[i - 1][j] > dp[i][j - 1]) ? dp[i - 1][j] : dp[i][j - 1];
            }
        }
    }

    return (n - dp[n][m]) + (m - dp[n][m]);
}

int main() {
    char str1[] = "heap";
    char str2[] = "pea";
    printf("Minimum operations: %d\n", minOperations(str1, str2));
    return 0;
}

